20	// source custom dest
21	// 1.0    -      1.0 (up-to-date)
22	// 2.0    -      1.0  --> Update: 2.0
23	// 1.0    X      1.0  --> Update: 1.0.custom.X
24	// 2.0    X      1.0  --> Update: 2.0.custom.X
25	// 1.0    X      1.0.custom.X (up-to-date)
26	// 2.0    X      1.0.custom.X  --> Update: 2.0.custom.X
27	// 1.0    X      2.0  --> Update: 2.0.custom.X
28	// 1.0    X      2.0.custom.X (up-to-date)
29	// 1.0    Y      1.0.custom.X  --> Update: 1.0.custom.Y
30	//
31	// DEPRECATED: in favor of auto-patch config compiler plugin
32	bool Customizer::UpdateConfigFile() {
33	  bool need_update = false;
34	  bool redistribute = false;
35	  bool missing_original_copy = false;
36	  string source_version;
37	  string dest_version;
38	  string applied_customization;
39	
40	  Config dest_config;
41	  if (dest_config.LoadFromFile(dest_path_)) {
42	    dest_config.GetString(version_key_, &dest_version);
43	    dest_config.GetString("customization", &applied_customization);
44	  }
45	  if (fs::exists(source_path_) && fs::exists(dest_path_) &&
46	      fs::equivalent(source_path_, dest_path_)) {
47	    missing_original_copy = true;
48	    source_version = dest_version;
49	  } else {
50	    Config source_config;
51	    if (source_config.LoadFromFile(source_path_)) {
52	      source_config.GetString(version_key_, &source_version);
53	    } else {
54	      LOG(ERROR) << "Error loading config from '" << source_path_ << "'.";
55	      return false;
56	    }
57	    if (CompareVersionString(source_version, dest_version) > 0) {
58	      need_update = true;
59	      redistribute = true;
60	    }
61	  }
62	
63	  path custom_path(dest_path_);
64	  if (custom_path.extension() != ".yaml") {
65	    custom_path.clear();
66	  } else {
67	    custom_path.replace_extension();
68	    if (custom_path.extension() == ".schema") {
69	      custom_path.replace_extension();
70	    }
71	    custom_path += ".custom.yaml";
72	  }
73	  string customization;
74	  if (!custom_path.empty() && fs::exists(custom_path)) {
75	    customization = std::to_string(Checksum(custom_path));
76	  }
77	  if (applied_customization != customization) {
78	    need_update = true;
79	  }
80	
81	  if (!need_update) {
82	    LOG(INFO) << "config file '" << dest_path_ << "' is up-to-date.";
83	    return false;
84	  }
85	  LOG(INFO) << "updating config file '" << dest_path_ << "'.";
86	
87	  bool is_dirty = !applied_customization.empty();
88	  if (redistribute || (is_dirty && !missing_original_copy)) {
89	    try {
90	      fs::copy_file(source_path_, dest_path_,
91	                    fs::copy_options::overwrite_existing);
92	    } catch (...) {
93	      LOG(ERROR) << "Error copying config file '" << source_path_
94	                 << "' to user directory.";
95	      return false;
96	    }
97	  }
98	  if (!customization.empty()) {
99	    if (missing_original_copy) {
100	      LOG(WARNING) << "patching user config without a shared original copy "
101	                      "is discouraged.";
102	    }
103	    LOG(INFO) << "applying customization file: " << custom_path;
104	    if (!dest_config.LoadFromFile(dest_path_)) {
105	      LOG(ERROR) << "Error reloading destination config file.";
106	      return false;
107	    }
108	    // applying patch
109	    Config custom_config;
110	    if (!custom_config.LoadFromFile(custom_path)) {
111	      LOG(ERROR) << "Error loading customization file.";
112	      return false;
113	    }
114	    if (auto patch = custom_config.GetMap("patch")) {
115	      for (auto it = patch->begin(); it != patch->end(); ++it) {
116	        if (!dest_config.SetItem(it->first, it->second)) {
117	          LOG(ERROR) << "Error applying customization: '" << it->first << "'.";
118	          return false;
119	        }
120	      }
121	    } else {
122	      LOG(WARNING) << "'patch' not found in customization file.";
123	    }
124	    // update config version
125	    dest_config.GetString(version_key_, &dest_version);
126	    size_t custom_part = dest_version.find(".custom.");
127	    if (custom_part != string::npos) {
128	      dest_version.erase(custom_part);
129	    }
130	    dest_version.append(".custom.").append(customization);
131	    dest_config.SetString(version_key_, dest_version);
132	    dest_config.SetString("customization", customization);
133	    if (!dest_config.SaveToFile(dest_path_)) {
134	      LOG(ERROR) << "Error saving destination config file.";
135	      return false;
136	    }
137	  }
138	
139	  return true;
140	}
