7	#include <boost/algorithm/string.hpp>
8	#include <rime/config.h>
9	#include <rime/deployer.h>
10	#include <rime/signature.h>
11	#include <rime/lever/custom_settings.h>
12	
13	namespace rime {
14	
15	static string remove_suffix(const string& input, const string& suffix) {
16	  return boost::ends_with(input, suffix)
17	             ? input.substr(0, input.length() - suffix.length())
18	             : input;
19	}
20	
21	static string custom_config_file(const string& config_id) {
22	  return remove_suffix(config_id, ".schema") + ".custom.yaml";
23	}
24	
25	CustomSettings::CustomSettings(Deployer* deployer,
26	                               const string& config_id,
27	                               const string& generator_id)
28	    : deployer_(deployer), config_id_(config_id), generator_id_(generator_id) {}
29	
30	bool CustomSettings::Load() {
31	  path config_path = deployer_->staging_dir / (config_id_ + ".yaml");
32	  if (!config_.LoadFromFile(config_path)) {
33	    config_path = deployer_->prebuilt_data_dir / (config_id_ + ".yaml");
34	    if (!config_.LoadFromFile(config_path)) {
35	      LOG(WARNING) << "cannot find '" << config_id_ << ".yaml'.";
36	    }
37	  }
38	  path custom_config_path =
39	      deployer_->user_data_dir / custom_config_file(config_id_);
40	  modified_ = false;
41	  if (!custom_config_.LoadFromFile(custom_config_path)) {
42	    LOG(WARNING) << "cannot find '" << config_id_ << ".custom.yaml'"
43	                 << " in " << custom_config_path;
44	    return false;
45	  }
46	  return true;
47	}
48	
49	bool CustomSettings::Save() {
50	  if (!modified_)
51	    return false;
52	  Signature signature(generator_id_, "customization");
53	  signature.Sign(&custom_config_, deployer_);
54	  path custom_config_path(deployer_->user_data_dir);
55	  custom_config_path /= custom_config_file(config_id_);
56	  custom_config_.SaveToFile(custom_config_path);
57	  modified_ = false;
58	  return true;
59	}
60	
61	an<ConfigValue> CustomSettings::GetValue(const string& key) {
62	  return config_.GetValue(key);
63	}
64	
65	an<ConfigList> CustomSettings::GetList(const string& key) {
66	  return config_.GetList(key);
67	}
68	
69	an<ConfigMap> CustomSettings::GetMap(const string& key) {
70	  return config_.GetMap(key);
71	}
72	
73	bool CustomSettings::Customize(const string& key, const an<ConfigItem>& item) {
74	  auto patch = custom_config_.GetMap("patch");
75	  if (!patch) {
76	    patch = New<ConfigMap>();
77	  }
78	  patch->Set(key, item);
79	  // the branch 'patch' should be set as a whole in order to be saved, for
80	  // its sub-key may contain slashes which disables directly setting a sub-item
81	  custom_config_.SetItem("patch", patch);
82	  modified_ = true;
83	  return true;
84	}
85	
86	bool CustomSettings::IsFirstRun() {
87	  path custom_config_path =
88	      deployer_->user_data_dir / custom_config_file(config_id_);
89	  Config config;
90	  if (!config.LoadFromFile(custom_config_path))
91	    return true;
92	  return !config.GetMap("customization");
93	}
94	
95	}  // namespace rime
