156	  if (!legacy_component)
157	    return true;
158	  the<Db> legacy_db(legacy_component->Create(dict_name));
159	  if (!legacy_db->Exists())
160	    return true;
161	  if (!legacy_db->OpenReadOnly() || !UserDbHelper(legacy_db).IsUserDb())
162	    return false;
163	  LOG(INFO) << "upgrading user dict '" << dict_name << "'.";
164	  path trash = deployer_->user_data_dir / "trash";
165	  if (!fs::exists(trash)) {
166	    std::error_code ec;
167	    if (!fs::create_directories(trash, ec)) {
168	      LOG(ERROR) << "error creating directory '" << trash << "'.";
169	      return false;
170	    }
171	  }
172	  string snapshot_file = dict_name + UserDb::snapshot_extension();
173	  path snapshot_path = trash / snapshot_file;
