178	bool UserDictManager::Synchronize(const string& dict_name) {
179	  LOG(INFO) << "synchronize user dict '" << dict_name << "'.";
180	  bool success = true;
181	  path sync_dir(deployer_->sync_dir);
182	  if (!fs::exists(sync_dir)) {
183	    std::error_code ec;
184	    if (!fs::create_directories(sync_dir, ec)) {
185	      LOG(ERROR) << "error creating directory '" << sync_dir << "'.";
186	      return false;
187	    }
188	  }
189	  // *.userdb.txt
190	  string snapshot_file = dict_name + UserDb::snapshot_extension();
191	  for (fs::directory_iterator it(sync_dir), end; it != end; ++it) {
192	    if (!fs::is_directory(it->path()))
193	      continue;
194	    path file_path = path(it->path()) / snapshot_file;
195	    if (fs::exists(file_path)) {
196	      LOG(INFO) << "merging snapshot file: " << file_path;
197	      if (!Restore(file_path)) {
198	        LOG(ERROR) << "failed to merge snapshot file: " << file_path;
199	        success = false;
200	      }
201	    }
202	  }
203	  if (!Backup(dict_name)) {
204	    LOG(ERROR) << "error backing up user dict '" << dict_name << "'.";
205	    success = false;
206	  }
207	  return success;
208	}
