210	bool UserDictManager::SynchronizeAll() {
211	  UserDictList user_dicts;
212	  GetUserDictList(&user_dicts);
213	  LOG(INFO) << "synchronizing " << user_dicts.size() << " user dicts.";
214	  int failure = 0;
215	  for (const string& dict_name : user_dicts) {
216	    if (!Synchronize(dict_name))
217	      ++failure;
218	  }
219	  if (failure) {
220	    LOG(ERROR) << "failed synchronizing " << failure << "/" << user_dicts.size()
221	               << " user dicts.";
222	  }
223	  return !failure;
224	}
