166	bool WorkspaceUpdate::Run(Deployer* deployer) {
167	  LOG(INFO) << "updating workspace.";
168	  {
169	    the<DeploymentTask> t;
170	    t.reset(new ConfigFileUpdate("default.yaml", "config_version"));
171	    t->Run(deployer);
172	    // Deprecated: symbols.yaml is only used as source file
173	    // t.reset(new ConfigFileUpdate("symbols.yaml", "config_version"));
174	    // t->Run(deployer);
175	    t.reset(new SymlinkingPrebuiltDictionaries);
176	    t->Run(deployer);
177	  }
178	
179	  the<Config> config(Config::Require("config")->Create("default"));
180	  if (!config) {
181	    LOG(ERROR) << "Error loading default config.";
182	    return false;
183	  }
184	  auto schema_list = config->GetList("schema_list");
185	  if (!schema_list) {
186	    LOG(WARNING) << "schema list not defined.";
187	    return false;
188	  }
189	
190	  LOG(INFO) << "updating schemas.";
191	  int success = 0;
192	  int failure = 0;
193	  map<string, path> schemas;
194	  the<ResourceResolver> resolver(Service::instance().CreateResourceResolver(
195	      {"schema_source_file", "", ".schema.yaml"}));
196	  auto build_schema = [&](const string& schema_id, bool as_dependency = false) {
197	    if (schemas.find(schema_id) != schemas.end())  // already built
198	      return;
199	    LOG(INFO) << "schema: " << schema_id;
200	    path schema_path;
201	    if (schemas.find(schema_id) == schemas.end()) {
202	      schema_path = resolver->ResolvePath(schema_id);
203	      schemas[schema_id] = schema_path;
204	    } else {
205	      schema_path = schemas[schema_id];
206	    }
207	    if (schema_path.empty() || !fs::exists(schema_path)) {
208	      if (as_dependency) {
209	        LOG(WARNING) << "missing input schema; skipped unsatisfied dependency: "
210	                     << schema_id;
211	      } else {
212	        LOG(ERROR) << "missing input schema: " << schema_id;
213	        ++failure;
214	      }
215	      return;
216	    }
217	    the<DeploymentTask> t(new SchemaUpdate(schema_path));
218	    if (t->Run(deployer))
219	      ++success;
220	    else
221	      ++failure;
222	  };
223	  auto schema_component = Config::Require("schema");
224	  for (auto it = schema_list->begin(); it != schema_list->end(); ++it) {
225	    auto item = As<ConfigMap>(*it);
226	    if (!item)
227	      continue;
228	    auto schema_property = item->GetValue("schema");
229	    if (!schema_property)
230	      continue;
231	    const string& schema_id = schema_property->str();
232	    build_schema(schema_id);
233	    the<Config> schema_config(schema_component->Create(schema_id));
234	    if (!schema_config)
235	      continue;
236	    if (auto dependencies = schema_config->GetList("schema/dependencies")) {
237	      for (auto d = dependencies->begin(); d != dependencies->end(); ++d) {
238	        auto dependency = As<ConfigValue>(*d);
239	        if (!dependency)
240	          continue;
241	        const string& dependency_id = dependency->str();
242	        bool as_dependency = true;
243	        build_schema(dependency_id, as_dependency);
244	      }
245	    }
246	  }
247	  LOG(INFO) << "finished updating schemas: " << success << " success, "
248	            << failure << " failure.";
249	
250	  the<Config> user_config(Config::Require("user_config")->Create("user"));
251	  // TODO: store as 64-bit number to avoid the year 2038 problem
252	  user_config->SetInt("var/last_build_time", (int)time(NULL));
253	
254	  return failure == 0;
255	}
