278	static bool RemoveVersionSuffix(string* version, const string& suffix) {
279	  size_t suffix_pos = version->find(suffix);
280	  if (suffix_pos != string::npos) {
281	    version->erase(suffix_pos);
282	    return true;
283	  }
284	  return false;
