287	static bool TrashDeprecatedUserCopy(const path& shared_copy,
288	                                    const path& user_copy,
289	                                    const string& version_key,
290	                                    const path& trash) {
291	  if (!fs::exists(shared_copy) || !fs::exists(user_copy) ||
292	      fs::equivalent(shared_copy, user_copy)) {
293	    return false;
294	  }
295	  string shared_copy_version;
296	  string user_copy_version;
297	  Config shared_config;
298	  if (shared_config.LoadFromFile(shared_copy)) {
299	    shared_config.GetString(version_key, &shared_copy_version);
300	    // treat "X.Y.minimal" as equal to (not greater than) "X.Y"
301	    // to avoid trashing the user installed full version
302	    RemoveVersionSuffix(&shared_copy_version, ".minimal");
303	  }
304	  Config user_config;
305	  bool is_customized_user_copy =
306	      user_config.LoadFromFile(user_copy) &&
307	      user_config.GetString(version_key, &user_copy_version) &&
308	      RemoveVersionSuffix(&user_copy_version, ".custom.");
309	  int cmp = CompareVersionString(shared_copy_version, user_copy_version);
310	  // rime-installed user copy of the same version should be kept for integrity.
311	  // also it could have been manually edited by user.
312	  if (cmp > 0 || (cmp == 0 && is_customized_user_copy)) {
313	    if (!MaybeCreateDirectory(trash)) {
314	      return false;
315	    }
316	    path backup = trash / user_copy.filename();
317	    std::error_code ec;
318	    fs::rename(user_copy, backup, ec);
319	    if (ec) {
320	      LOG(ERROR) << "error trashing file " << user_copy;
321	      return false;
322	    }
323	    return true;
324	  }
325	  return false;
326	}
