328	bool SchemaUpdate::Run(Deployer* deployer) {
329	  if (!fs::exists(source_path_)) {
330	    LOG(ERROR) << "Error updating schema: nonexistent file '" << source_path_
331	               << "'.";
332	    return false;
333	  }
334	  string schema_id;
335	  the<Config> config(new Config);
336	  if (!config->LoadFromFile(source_path_) ||
337	      !config->GetString("schema/schema_id", &schema_id) || schema_id.empty()) {
338	    LOG(ERROR) << "invalid schema definition in '" << source_path_ << "'.";
339	    return false;
340	  }
341	
342	  the<DeploymentTask> config_file_update(
343	      new ConfigFileUpdate(schema_id + ".schema.yaml", "schema/version"));
344	  if (!config_file_update->Run(deployer)) {
345	    return false;
346	  }
347	  // reload compiled config
348	  config.reset(Config::Require("schema")->Create(schema_id));
349	  string dict_name;
350	  if (!config->GetString("translator/dictionary", &dict_name)) {
351	    // not requiring a dictionary
352	    return true;
353	  }
354	  Schema schema(schema_id, config.release());
355	  the<Dictionary> dict(
356	      Dictionary::Require("dictionary")->Create({&schema, "translator"}));
357	  if (!dict) {
358	    LOG(ERROR) << "Error creating dictionary '" << dict_name << "'.";
359	    return false;
360	  }
361	
362	  LOG(INFO) << "preparing dictionary '" << dict_name << "'.";
363	  const path& user_data_path(deployer->user_data_dir);
364	  if (!MaybeCreateDirectory(deployer->staging_dir)) {
365	    return false;
366	  }
367	  DictCompiler dict_compiler(dict.get());
368	  if (verbose_) {
369	    dict_compiler.set_options(DictCompiler::kRebuild | DictCompiler::kDump);
370	  }
371	  the<ResourceResolver> resolver(
372	      Service::instance().CreateDeployedResourceResolver(
373	          {"compiled_schema", "", ".schema.yaml"}));
374	  auto compiled_schema = resolver->ResolvePath(schema_id);
375	  if (!dict_compiler.Compile(compiled_schema)) {
376	    LOG(ERROR) << "dictionary '" << dict_name << "' failed to compile.";
377	    return false;
378	  }
379	  LOG(INFO) << "dictionary '" << dict_name << "' is ready.";
380	  return true;
381	}
