472	bool SymlinkingPrebuiltDictionaries::Run(Deployer* deployer) {
473	  const path shared_data_path(deployer->shared_data_dir);
474	  const path user_data_path(deployer->user_data_dir);
475	  if (!fs::exists(shared_data_path) || !fs::is_directory(shared_data_path) ||
476	      !fs::exists(user_data_path) || !fs::is_directory(user_data_path) ||
477	      fs::equivalent(shared_data_path, user_data_path))
478	    return false;
479	  bool success = false;
480	  // remove symlinks to shared data files created by previous version
481	  for (fs::directory_iterator test(user_data_path), end; test != end; ++test) {
482	    path entry(test->path());
483	    if (fs::is_symlink(entry)) {
484	      try {
485	        // a symlink becomes dangling if the target file is no longer provided
486	        std::error_code ec;
487	        auto target_path = fs::canonical(entry, ec);
488	        bool bad_link = bool(ec);
489	        bool linked_to_shared_data =
490	            !bad_link && target_path.has_parent_path() &&
491	            fs::equivalent(shared_data_path, target_path.parent_path());
492	        if (bad_link || linked_to_shared_data) {
493	          LOG(INFO) << "removing symlink: " << entry.filename();
494	          fs::remove(entry);
495	        }
496	      } catch (const fs::filesystem_error& ex) {
497	        LOG(ERROR) << entry << ": " << ex.what();
498	        success = false;
499	      }
500	    }
501	  }
502	  return success;
503	}
