541	bool BackupConfigFiles::Run(Deployer* deployer) {
542	  if (!deployer->backup_config_files) {
543	    LOG(INFO) << "skip backing up config files because it's disabled.";
544	    return true;
545	  }
546	  LOG(INFO) << "backing up config files.";
547	  const path user_data_path(deployer->user_data_dir);
548	  if (!fs::exists(user_data_path))
549	    return false;
550	  path backup_dir(deployer->user_data_sync_dir());
551	  if (!MaybeCreateDirectory(backup_dir)) {
552	    return false;
553	  }
554	  int success = 0, failure = 0, latest = 0, skipped = 0;
555	  for (fs::directory_iterator iter(user_data_path), end; iter != end; ++iter) {
556	    path entry(iter->path());
557	    if (!fs::is_regular_file(entry))
558	      continue;
559	    auto file_extension = entry.extension().u8string();
560	    bool is_yaml_file = file_extension == ".yaml";
561	    bool is_text_file = file_extension == ".txt";
562	    if (!is_yaml_file && !is_text_file)
563	      continue;
564	    path backup = backup_dir / entry.filename();
565	    if (fs::exists(backup) && Checksum(backup) == Checksum(entry)) {
566	      ++latest;  // already up-to-date
567	      continue;
568	    }
569	    if (is_yaml_file && IsCustomizedCopy(entry)) {
570	      ++skipped;  // customized copy
571	      continue;
572	    }
573	    std::error_code ec;
574	    fs::copy_file(entry, backup, fs::copy_options::overwrite_existing, ec);
575	    if (ec) {
576	      LOG(ERROR) << "error backing up file " << backup;
577	      ++failure;
578	    } else {
579	      ++success;
580	    }
581	  }
582	  LOG(INFO) << "backed up " << success << " config files to " << backup_dir
583	            << ", " << failure << " failed, " << latest << " up-to-date, "
584	            << skipped << " skipped.";
585	  return !failure;
586	}
