624	bool CleanOldLogFiles::Run(Deployer* deployer) {
625	  bool success = true;
626	#ifdef RIME_ENABLE_LOGGING
627	  if (FLAGS_logtostderr || FLAGS_log_dir.empty()) {
628	    return success;
629	  }
630	
631	  char ymd[12] = {0};
632	  time_t now = time(NULL);
633	  strftime(ymd, sizeof(ymd), ".%Y%m%d", localtime(&now));
634	  string today(ymd);
635	  DLOG(INFO) << "today: " << today;
636	
637	  vector<string> dirs(google::GetLoggingDirectories());
638	
639	  DLOG(INFO) << "scanning " << dirs.size() << " temp directory for log files.";
640	
641	  int removed = 0;
642	  const string& app_name = deployer->app_name;
643	  for (const auto& dir : dirs) {
644	    // avoid iteration on non-existing directory, which may cause error
645	    if (!fs::exists(fs::path(dir)))
646	      continue;
647	    vector<path> files_to_remove;
648	    set<path> files_in_use;
649	    DLOG(INFO) << "temp directory: " << dir;
650	    try {
651	      // preparing files
652	      for (const auto& entry : fs::directory_iterator(dir)) {
653	        const string& file_name(entry.path().filename().u8string());
654	        if (entry.is_regular_file() && !entry.is_symlink() &&
655	            boost::starts_with(file_name, app_name) &&
656	            boost::ends_with(file_name, ".log") &&
657	            !boost::contains(file_name, today)) {
658	          files_to_remove.push_back(entry.path());
659	        } else if (entry.is_symlink()) {
660	          auto target = fs::read_symlink(entry.path());
661	          const string& target_file_name(target.filename().u8string());
662	          if (boost::starts_with(target_file_name, app_name) &&
663	              boost::ends_with(target_file_name, ".log")) {
664	            files_in_use.insert(target);
665	          }
666	        }
667	      }
668	    } catch (const fs::filesystem_error& ex) {
669	      // Catch error to skip up when we have no sufficient permissions.
670	      // E.g. on Android, there's no read permission on the cwd.
671	      LOG(WARNING) << "couldn't list directory '" << dir << "': " << ex.what();
672	      continue;
673	    }
674	    // remove files
675	    for (const auto& file : files_to_remove) {
676	      if (files_in_use.find(file.filename()) != files_in_use.end())
677	        continue;
678	      try {
679	        DLOG(INFO) << "removing log file '" << file.filename() << "'.";
680	        // ensure write permission
681	        fs::permissions(file, fs::perms::owner_write);
682	        fs::remove(file);
683	        ++removed;
684	      } catch (const fs::filesystem_error& ex) {
685	        LOG(ERROR) << ex.what();
686	        success = false;
687	      }
688	    }
689	  }
690	  if (removed != 0) {
691	    LOG(INFO) << "cleaned " << removed << " log files.";
692	  }
693	#endif  // RIME_ENABLE_LOGGING
694	  return success;
695	}
